// src/pages/SellerDashboard.js
import React, { useState, useEffect } from "react";
import axios from "axios";
import "./SellerDashboard.css";

function SellerDashboard() {
  const [products, setProducts] = useState([]);
  const [form, setForm] = useState({
    name: "",
    description: "",
    category: "Earphone",
    price: "",
    offerPrice: "",
    image: ""
  });

  const [activePage, setActivePage] = useState("add"); // add | list | orders

  // Fetch products when component loads
  useEffect(() => {
    fetchProducts();
  }, []);

  const fetchProducts = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/products");
      setProducts(res.data);
    } catch (err) {
      console.error("❌ Failed to fetch products:", err);
    }
  };

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post("http://localhost:5000/api/products", form);
      setProducts([...products, res.data]); // add new one locally
      setForm({
        name: "",
        description: "",
        category: "Earphone",
        price: "",
        offerPrice: "",
        image: ""
      });
      alert("✅ Product added successfully!");
    } catch (err) {
      console.error(err);
      alert("❌ Failed to add product");
    }
  };

  return (
    <div className="seller-dashboard">
      {/* Sidebar */}
      <aside className="sidebar">
        <h1 className="logo">Seller</h1>
        <nav>
          <ul>
            <li
              className={activePage === "add" ? "active" : ""}
              onClick={() => setActivePage("add")}
            >
              ➕ Add Product
            </li>
            <li
              className={activePage === "list" ? "active" : ""}
              onClick={() => setActivePage("list")}
            >
              📦 Product List
            </li>
            <li
              className={activePage === "orders" ? "active" : ""}
              onClick={() => setActivePage("orders")}
            >
              📝 Orders
            </li>
          </ul>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="main-content">
        {activePage === "add" && (
          <>
            <h2 className="page-title">Add Product</h2>
            <form className="product-form" onSubmit={handleSubmit}>
              <label>Product Name</label>
              <input
                type="text"
                name="name"
                placeholder="Type here"
                value={form.name}
                onChange={handleChange}
                required
              />

              <label>Product Description</label>
              <textarea
                name="description"
                placeholder="Type here"
                value={form.description}
                onChange={handleChange}
              ></textarea>

              <label>Image URL</label>
              <input
                type="text"
                name="image"
                placeholder="https://..."
                value={form.image}
                onChange={handleChange}
                required
              />

              <div className="row">
                <div>
                  <label>Category</label>
                  <select
                    name="category"
                    value={form.category}
                    onChange={handleChange}
                  >
                    <option>Earphone</option>
                    <option>Smartphone</option>
                    <option>Laptop</option>
                    <option>Smartwatch</option>
                    <option>Other</option>
                  </select>
                </div>

                <div>
                  <label>Product Price</label>
                  <input
                    type="number"
                    name="price"
                    placeholder="0"
                    value={form.price}
                    onChange={handleChange}
                    required
                  />
                </div>

                <div>
                  <label>Offer Price</label>
                  <input
                    type="number"
                    name="offerPrice"
                    placeholder="0"
                    value={form.offerPrice}
                    onChange={handleChange}
                  />
                </div>
              </div>

              <button type="submit" className="add-btn">
                ADD
              </button>
            </form>
          </>
        )}

        {activePage === "list" && (
          <>
            <h2 className="page-title">Your Product List</h2>
            <div className="product-list">
              {products.length > 0 ? (
                products.map((p, idx) => (
                  <div key={idx} className="product-card">
                    {p.image && <img src={p.image} alt={p.name} width="120" />}
                    <h4>{p.name}</h4>
                    <p>{p.description}</p>
                    <p>
                      <b>Category:</b> {p.category}
                    </p>
                    <p>
                      <b>Price:</b> ₹{p.price}
                    </p>
                    {p.offerPrice && (
                      <p>
                        <b>Offer:</b> ₹{p.offerPrice}
                      </p>
                    )}
                  </div>
                ))
              ) : (
                <p>No products yet.</p>
              )}
            </div>
          </>
        )}

        {activePage === "orders" && (
          <h2 className="page-title">Orders (coming soon...)</h2>
        )}
      </main>
    </div>
  );
}

export default SellerDashboard;
